def get_weapon(wid):
    for p in [PRIMARIES,SECONDARIES,GRENADES]:
        if wid in p:return p[wid]
    return None

def get_all_weapons():
    r=[]
    r.extend(PRIMARIES.values())
    r.extend(SECONDARIES.values())
    r.extend(GRENADES.values())
    return r
